class Solution:
    def sortByBits(self, arr):
        def bits(x):
            c = 0
            while x:
                c += x & 1
                x >>= 1
            return c
        out = list(arr)
        n = len(out)
        for i in range(n):
            for j in range(n - 1 - i):
                a, b = out[j], out[j + 1]
                if (bits(a), a) > (bits(b), b):
                    out[j], out[j + 1] = out[j + 1], out[j]
        return out

