var sortByBits = function(arr) {
    const pc = (x) => { let c = 0; while (x) { c += x & 1; x >>>= 1; } return c; };
    return arr.slice().sort((a, b) => {
        const d = pc(a) - pc(b);
        return d !== 0 ? d : a - b;
    });
};
